 */
public static int nextPrime(int desiredCapacity) {
    if (desiredCapacity <= 1) {
        return 2;
    }
    int capacity = desiredCapacity;
    if (capacity % 2 == 0) {
        capacity++;
    }
    while (true) {
        if (isPrime(capacity)) {
