 */
public static int nextPrime(int desiredCapacity) {
    if (desiredCapacity <= 1) {
        return 2;
    }
    int prime = desiredCapacity;
    boolean found = false;
    while (!found) {
        if (isPrime(prime)) {
            found = true;
        } else {
            prime++;
        }
    }
    if (desiredCapacity >= 1000) {
        int upperLimit = (int) (desiredCapacity * 1.11);
        while (prime < upperLimit) {
