private static int digitValue(final char c) {
    if (c >= '0' && c <= '9') {
        // ASCII '0' to '9'
        return c - '0';
    } else if (c >= 'A' && c <= 'Z') {
        // ASCII 'A' to 'Z'
        return c - 'A' + 10;
