/**
 * $n$ का फैक्टरियल निकालें।
 * @param n इनपुट संख्या
 * @return फैक्टरियल
 */
public static long factorial(int n) {
    if (n < 0) {
        throw new IllegalArgumentException("Negative numbers do not have factorials.");
    }
    long result = 1;
    for (int i = 2; i <= n; i++) {
        result *= i;
    }
    return result;
}

