public boolean isCompatible(DataTable dataset) {
    String[] datasetBuckets = dataset.getBuckets();
    if (myBuckets.length != datasetBuckets.length) {
        return false;
    }
    for (int i = 0; i < myBuckets.length; i++) {
        if (!myBuckets[i].equals(datasetBuckets[i])) {
            return false;
        }
    }
    return true;
}

